import{_ as a,o as l,c as r,ag as i}from"./chunks/framework.CNG7EpJN.js";const c=JSON.parse('{"title":"Part 5 — 予約管理","description":"","frontmatter":{"title":"Part 5 — 予約管理","audience":"オーナー / 店長 / ホールスタッフ","prerequisite":"Part 0 + Part 1","last_updated":"2026-04-18T00:00:00.000Z"},"headers":[],"relativePath":"operations/part5-reservations.md","filePath":"operations/part5-reservations.md"}'),o={name:"operations/part5-reservations.md"};function n(e,t,s,d,h,g){return l(),r("div",null,[...t[0]||(t[0]=[i(`<h1 id="part-5-—-予約管理" tabindex="-1">Part 5 — 予約管理 <a class="header-anchor" href="#part-5-—-予約管理" aria-label="Permalink to &quot;Part 5 — 予約管理&quot;">​</a></h1><p>このページでは、お客様からの予約受付・管理を、<strong>実際にマウスで押すボタン</strong> を 1 つずつ順番に説明します。</p><div class="tip custom-block"><p class="custom-block-title">この章の対象</p><ul><li>飲食店で <strong>電話予約を受ける</strong> / <strong>お客様がオンラインで予約を入れる</strong> / <strong>予約客が来店したときの着席</strong> / <strong>無断キャンセル管理</strong> の一連を確認できます。</li><li>予約管理の全体像を詳しく確認したい場合は、<a href="./../tenant/24-reservations.html">24 章「予約管理」</a> も参照してください。</li></ul></div><hr><h2 id="_5-0-予約管理とは" tabindex="-1">5-0. 予約管理とは？ <a class="header-anchor" href="#_5-0-予約管理とは" aria-label="Permalink to &quot;5-0. 予約管理とは？&quot;">​</a></h2><p>POSLA の予約管理は、お客様が来店する前日までに「何時に何人で行きます」と申し込む仕組みです。以下の機能があります。</p><ol><li><strong>オンライン予約</strong>: お客様が自分のスマホで予約 LP（ランディングページ）から予約できる</li><li><strong>電話予約</strong>: マネージャー以上がハンディまたは管理画面から手動で予約を登録できる</li><li><strong>AI 予約</strong>: お客様が自由文（例: 「明日 19 時 2 名田中」）で予約できる、AI が解析</li><li><strong>予約金徴収</strong>: お客様にカードを登録してもらい、来店したら解除、無断キャンセル時に請求</li><li><strong>自動着席</strong>: 予約客が QR を読むとスタッフ操作なしで自動着席</li><li><strong>ガント台帳</strong>: 時間 × テーブルのマトリクスで予約状況を見える化</li></ol><hr><h2 id="_5-1-予約-lp-お客様向けページ-の-url-取得と掲載" tabindex="-1">5-1. 予約 LP（お客様向けページ）の URL 取得と掲載 <a class="header-anchor" href="#_5-1-予約-lp-お客様向けページ-の-url-取得と掲載" aria-label="Permalink to &quot;5-1. 予約 LP（お客様向けページ）の URL 取得と掲載&quot;">​</a></h2><h3 id="_5-1-1-url-qr-を確認する" tabindex="-1">5-1-1. URL / QR を確認する <a class="header-anchor" href="#_5-1-1-url-qr-を確認する" aria-label="Permalink to &quot;5-1-1. URL / QR を確認する&quot;">​</a></h3><ol><li>管理画面にログイン</li><li>上部タブから <strong>【店舗設定】</strong> をクリック</li><li>サブタブから <strong>【店舗設定】</strong> を選択</li><li>画面を下にスクロール</li><li><strong>「📅 予約ページ」</strong> セクションが見える</li><li>以下の 4 つのボタンと情報が表示されている:</li></ol><table tabindex="0"><thead><tr><th>要素</th><th>用途</th></tr></thead><tbody><tr><td><strong>URL 表示</strong></td><td>お客様に案内する予約ページの URL</td></tr><tr><td><strong>QR コード画像</strong></td><td>上記 URL を QR に変換したもの</td></tr><tr><td><strong>【URL をコピー】</strong></td><td>クリップボードに URL を保存（LINE / メールで送信用）</td></tr><tr><td><strong>【新タブで開く】</strong></td><td>動作確認用</td></tr><tr><td><strong>【QR 画像コピー】</strong></td><td>Instagram 等に貼る用</td></tr><tr><td><strong>【🖨 印刷】</strong></td><td>A4 ポスターとして印刷</td></tr></tbody></table><h3 id="_5-1-2-どこに掲載する" tabindex="-1">5-1-2. どこに掲載する？ <a class="header-anchor" href="#_5-1-2-どこに掲載する" aria-label="Permalink to &quot;5-1-2. どこに掲載する？&quot;">​</a></h3><ul><li><strong>Instagram / X / Facebook</strong> などの SNS プロフィール欄に URL 貼り付け</li><li><strong>Google マイビジネス</strong> の「予約」リンク</li><li><strong>お店の公式ホームページ</strong></li><li><strong>店頭ポスター</strong>（印刷ボタンで出力して店頭に貼る）</li><li><strong>LINE 公式アカウント</strong> のメッセージ</li><li><strong>食べログの口コミ返信</strong> に予約 URL を入れる</li></ul><h3 id="_5-1-3-お客様が-url-から予約する流れ-5-ステップ" tabindex="-1">5-1-3. お客様が URL から予約する流れ（5 ステップ） <a class="header-anchor" href="#_5-1-3-お客様が-url-から予約する流れ-5-ステップ" aria-label="Permalink to &quot;5-1-3. お客様が URL から予約する流れ（5 ステップ）&quot;">​</a></h3><ol><li>お客様が URL / QR から予約 LP を開く</li><li><strong>日付選択</strong>（カレンダーから希望日をタップ）</li><li><strong>人数選択</strong>（1〜20 名程度）</li><li><strong>時刻スロット選択</strong>（空きのある時刻のみ緑で表示）</li><li><strong>お客様情報入力</strong>（名前・電話・メール・特記事項）</li><li><strong>確認画面</strong> → <strong>【予約する】</strong> ボタン</li><li>予約金を設定している店舗なら Stripe Checkout で決済へ</li><li>予約完了メールが自動送信される</li></ol><hr><h2 id="_5-2-ガント台帳の見方" tabindex="-1">5-2. ガント台帳の見方 <a class="header-anchor" href="#_5-2-ガント台帳の見方" aria-label="Permalink to &quot;5-2. ガント台帳の見方&quot;">​</a></h2><h3 id="_5-2-1-開く手順" tabindex="-1">5-2-1. 開く手順 <a class="header-anchor" href="#_5-2-1-開く手順" aria-label="Permalink to &quot;5-2-1. 開く手順&quot;">​</a></h3><ol><li>管理画面の上部タブから <strong>【予約管理】</strong> をタップ</li><li>サブタブから <strong>【予約台帳】</strong> を選択</li><li>画面が開く</li><li>画面上部に <strong>「今日」「‹」「日付入力」「›」</strong> のボタンで日付切替</li><li>本体は <strong>時間（縦軸）× テーブル（横軸）</strong> のマトリクス</li></ol><h3 id="_5-2-2-画面構成" tabindex="-1">5-2-2. 画面構成 <a class="header-anchor" href="#_5-2-2-画面構成" aria-label="Permalink to &quot;5-2-2. 画面構成&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 日付: 2026-04-19  [‹] [今日] [›]  予約数: 8  │</span></span>
<span class="line"><span>├────────┬────────┬────────┬────────┬────────┤</span></span>
<span class="line"><span>│ 時刻  │  T01   │  T02   │  T03   │  T04   │</span></span>
<span class="line"><span>├────────┼────────┼────────┼────────┼────────┤</span></span>
<span class="line"><span>│ 17:00 │  🟦田中 │        │        │        │</span></span>
<span class="line"><span>│ 17:30 │  (2名) │  🟦鈴木 │        │        │</span></span>
<span class="line"><span>│ 18:00 │        │  (4名) │        │ 🟨決済 │</span></span>
<span class="line"><span>│ 18:30 │        │        │  🟩在  │  待ち │</span></span>
<span class="line"><span>│ 19:00 │  🟥no  │        │  席中  │        │</span></span>
<span class="line"><span>│       │  show  │        │        │        │</span></span>
<span class="line"><span>└────────┴────────┴────────┴────────┴────────┘</span></span></code></pre></div><h3 id="_5-2-3-予約ブロックの色分け" tabindex="-1">5-2-3. 予約ブロックの色分け <a class="header-anchor" href="#_5-2-3-予約ブロックの色分け" aria-label="Permalink to &quot;5-2-3. 予約ブロックの色分け&quot;">​</a></h3><table tabindex="0"><thead><tr><th>色</th><th>意味</th><th>状態</th></tr></thead><tbody><tr><td>🟦 青</td><td>確定</td><td>通常の予約</td></tr><tr><td>🟨 黄</td><td>予約金決済待ち</td><td>予約金の決済がまだ完了していない予約</td></tr><tr><td>🟩 緑</td><td>着席中</td><td>QR 読み込み済み、またはスタッフが着席処理済み</td></tr><tr><td>🟥 赤</td><td>無断キャンセル</td><td>予約時刻を過ぎても来店がない予約</td></tr><tr><td>⚫ グレー</td><td>キャンセル</td><td>お客様または店舗がキャンセルした予約</td></tr></tbody></table><h3 id="_5-2-4-ブロックをクリックすると" tabindex="-1">5-2-4. ブロックをクリックすると？ <a class="header-anchor" href="#_5-2-4-ブロックをクリックすると" aria-label="Permalink to &quot;5-2-4. ブロックをクリックすると？&quot;">​</a></h3><p>予約の詳細モーダルが開き、以下の操作ができます:</p><ul><li><strong>【🪑 着席】</strong> — 手動で着席状態にする</li><li><strong>【無断キャンセル】</strong> — 無断キャンセルとして記録（予約金があれば請求）</li><li><strong>【✏️ 変更】</strong> — 時刻・人数・メモ変更</li><li><strong>【🗑 キャンセル】</strong> — 予約を取り消し</li></ul><hr><h2 id="_5-3-電話で予約を受けたときの登録手順" tabindex="-1">5-3. 電話で予約を受けたときの登録手順 <a class="header-anchor" href="#_5-3-電話で予約を受けたときの登録手順" aria-label="Permalink to &quot;5-3. 電話で予約を受けたときの登録手順&quot;">​</a></h2><p>お客様が電話で予約を入れたい場合、スタッフが手動で登録します。</p><h3 id="_5-3-1-ガント画面から登録" tabindex="-1">5-3-1. ガント画面から登録 <a class="header-anchor" href="#_5-3-1-ガント画面から登録" aria-label="Permalink to &quot;5-3-1. ガント画面から登録&quot;">​</a></h3><ol><li>管理画面 → 【予約管理】 → 【予約台帳】</li><li>画面上部の <strong>【+ 新規予約】</strong> ボタンをクリック</li><li>モーダルが開く</li><li>以下を入力:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>内容</th></tr></thead><tbody><tr><td>名前</td><td>✅</td><td>電話で聞いた氏名</td></tr><tr><td>電話番号</td><td>✅</td><td>10〜11 桁、ハイフンなし</td></tr><tr><td>メール</td><td>—</td><td>任意。予約確認メール送信用</td></tr><tr><td>日時</td><td>✅</td><td>予約日と時刻</td></tr><tr><td>人数</td><td>✅</td><td>来店予定人数</td></tr><tr><td>テーブル割当</td><td>—</td><td>チェックボックスで指定テーブル選択（未指定なら後で）</td></tr><tr><td>メモ</td><td>—</td><td>「アレルギー: 卵」「誕生日」等</td></tr><tr><td>タグ</td><td>—</td><td>VIP / 大事な接待 等のマーカー</td></tr></tbody></table><ol start="5"><li><strong>「予約金徴収をスキップ」</strong> チェックボックス（電話受付では通常 ON）</li><li><strong>【作成】</strong> ボタン</li><li>予約が作成され、ガント台帳にブロックが表示される</li></ol><div class="tip custom-block"><p class="custom-block-title">電話予約では予約金徴収をスキップする理由</p><p>電話越しにお客様にカード番号を伝えてもらうのは現実的でないため、電話予約では予約金徴収をスキップするのが普通です。ただし大型パーティー（10 名以上）などは、念のため予約金を徴収するよう検討してください。</p></div><h3 id="_5-3-2-ハンディから登録" tabindex="-1">5-3-2. ハンディから登録 <a class="header-anchor" href="#_5-3-2-ハンディから登録" aria-label="Permalink to &quot;5-3-2. ハンディから登録&quot;">​</a></h3><p>外出先や混雑時はハンディからも予約登録できます。</p><ol><li>ハンディ画面の <strong>【📅 予約】</strong> タブ</li><li>右下の <strong>【+ 新規】</strong> ボタン</li><li>同じくモーダルで入力</li><li>保存</li></ol><hr><h2 id="_5-4-予約なしで来店したお客様の登録" tabindex="-1">5-4. 予約なしで来店したお客様の登録 <a class="header-anchor" href="#_5-4-予約なしで来店したお客様の登録" aria-label="Permalink to &quot;5-4. 予約なしで来店したお客様の登録&quot;">​</a></h2><p>予約なしのお客様をすぐに着席・注文開始させる場合。</p><h3 id="手順" tabindex="-1">手順 <a class="header-anchor" href="#手順" aria-label="Permalink to &quot;手順&quot;">​</a></h3><ol><li>ハンディ画面の <strong>【テーブル状況】</strong> タブ</li><li>空きテーブル（T03）をタップ</li><li>画面に <strong>【+ 予約なし来店】</strong> ボタン → タップ</li><li>人数入力（例: 2 名）</li><li><strong>【着席】</strong></li><li>テーブルがセッション確立、メニュー注文開始できる</li></ol><p>予約なしのお客様として記録され、通常の来店と同じように注文・会計できます。</p><hr><h2 id="_5-5-予約客が来店したとき-自動着席の仕組み" tabindex="-1">5-5. 予約客が来店したとき（自動着席の仕組み） <a class="header-anchor" href="#_5-5-予約客が来店したとき-自動着席の仕組み" aria-label="Permalink to &quot;5-5. 予約客が来店したとき（自動着席の仕組み）&quot;">​</a></h2><p>POSLA では予約客が店に来て QR を読むと、条件が合えば <strong>スタッフ操作なしで自動的に着席状態</strong>になります。</p><h3 id="_5-5-1-自動着席の条件-3-つすべて必要" tabindex="-1">5-5-1. 自動着席の条件（3 つすべて必要） <a class="header-anchor" href="#_5-5-1-自動着席の条件-3-つすべて必要" aria-label="Permalink to &quot;5-5-1. 自動着席の条件（3 つすべて必要）&quot;">​</a></h3><ol><li><strong>テーブル割当済み</strong>（予約登録時に特定のテーブルを指定してあること）</li><li><strong>予約時刻 ±30 分以内</strong>（18:00 予約なら 17:30〜18:30 の間に QR を読む）</li><li><strong>予約が確定済み、または予約金の決済待ちであること</strong></li></ol><h3 id="_5-5-2-流れ" tabindex="-1">5-5-2. 流れ <a class="header-anchor" href="#_5-5-2-流れ" aria-label="Permalink to &quot;5-5-2. 流れ&quot;">​</a></h3><ol><li>予約客が来店</li><li>スタッフが該当テーブル（T03）に案内</li><li>お客様が T03 の QR をスマホで読む</li><li>POSLA側で自動マッチング（予約情報と照合）</li><li>マッチすれば即セッション確立 → お客様のメニュー画面が開く</li><li>ガント台帳のブロックが 🟦 青 → 🟩 緑（着席中）に変わる</li></ol><p><strong>お客様が注文を始められるまでスタッフの作業は 0 秒</strong>です。</p><hr><h2 id="_5-6-自動マッチングが成立しないときの手動着席" tabindex="-1">5-6. 自動マッチングが成立しないときの手動着席 <a class="header-anchor" href="#_5-6-自動マッチングが成立しないときの手動着席" aria-label="Permalink to &quot;5-6. 自動マッチングが成立しないときの手動着席&quot;">​</a></h2><p>以下の場合、自動着席が失敗します:</p><ul><li>テーブル未割当で予約された</li><li>予約時刻を 30 分以上過ぎて来店</li><li>お客様が違うテーブルの QR を読んだ</li></ul><h3 id="手動着席の手順" tabindex="-1">手動着席の手順 <a class="header-anchor" href="#手動着席の手順" aria-label="Permalink to &quot;手動着席の手順&quot;">​</a></h3><ol><li>ガント台帳で該当予約ブロックをタップ</li><li>モーダルに <strong>【🪑 着席】</strong> ボタン</li><li>タップ</li><li>テーブルを選択（未割当の場合）</li><li>着席状態に変わる</li></ol><hr><h2 id="_5-7-無断キャンセルの登録" tabindex="-1">5-7. 無断キャンセルの登録 <a class="header-anchor" href="#_5-7-無断キャンセルの登録" aria-label="Permalink to &quot;5-7. 無断キャンセルの登録&quot;">​</a></h2><p>予約時刻を過ぎても来店がない場合の対応。</p><h3 id="_5-7-1-タイミング" tabindex="-1">5-7-1. タイミング <a class="header-anchor" href="#_5-7-1-タイミング" aria-label="Permalink to &quot;5-7-1. タイミング&quot;">​</a></h3><p>通常、予約時刻から 30 分経過しても来店がない場合に無断キャンセルとして処理します。</p><h3 id="_5-7-2-手順" tabindex="-1">5-7-2. 手順 <a class="header-anchor" href="#_5-7-2-手順" aria-label="Permalink to &quot;5-7-2. 手順&quot;">​</a></h3><ol><li>ガント台帳で該当予約ブロックをタップ</li><li>モーダルに <strong>【無断キャンセル】</strong> ボタン</li><li>タップ</li><li>確認ダイアログで <strong>【OK】</strong></li><li>予約が赤色の無断キャンセル表示に変わる</li></ol><h3 id="_5-7-3-予約金の自動請求" tabindex="-1">5-7-3. 予約金の自動請求 <a class="header-anchor" href="#_5-7-3-予約金の自動請求" aria-label="Permalink to &quot;5-7-3. 予約金の自動請求&quot;">​</a></h3><p>予約金ありの店舗で無断キャンセルを登録すると、設定に従って予約金が請求されます。お客様のカードに反映される日はカード会社の処理状況により異なります。</p><hr><h2 id="_5-8-予約の変更・キャンセル" tabindex="-1">5-8. 予約の変更・キャンセル <a class="header-anchor" href="#_5-8-予約の変更・キャンセル" aria-label="Permalink to &quot;5-8. 予約の変更・キャンセル&quot;">​</a></h2><h3 id="_5-8-1-お客様側からの変更" tabindex="-1">5-8-1. お客様側からの変更 <a class="header-anchor" href="#_5-8-1-お客様側からの変更" aria-label="Permalink to &quot;5-8-1. お客様側からの変更&quot;">​</a></h3><p>お客様が予約確認メールに記載された URL を開くと、自分で変更・キャンセルできます。</p><ul><li>時刻変更</li><li>人数変更</li><li>メモ変更</li><li>キャンセル</li></ul><h3 id="_5-8-2-店舗側からの変更" tabindex="-1">5-8-2. 店舗側からの変更 <a class="header-anchor" href="#_5-8-2-店舗側からの変更" aria-label="Permalink to &quot;5-8-2. 店舗側からの変更&quot;">​</a></h3><ol><li>ガント台帳で予約ブロックをタップ</li><li><strong>【✏️ 変更】</strong> または <strong>【🗑 キャンセル】</strong></li><li>変更内容を入力 or キャンセル確認</li></ol><hr><h2 id="_5-9-コース予約の管理" tabindex="-1">5-9. コース予約の管理 <a class="header-anchor" href="#_5-9-コース予約の管理" aria-label="Permalink to &quot;5-9. コース予約の管理&quot;">​</a></h2><p>コース料理（懐石・フランス料理のプリフィックス等）の予約設定。</p><h3 id="_5-9-1-コース定義" tabindex="-1">5-9-1. コース定義 <a class="header-anchor" href="#_5-9-1-コース定義" aria-label="Permalink to &quot;5-9-1. コース定義&quot;">​</a></h3><ol><li>【予約管理】 → 【コース管理】サブタブ</li><li><strong>【+ コース追加】</strong></li><li>以下を入力: <ul><li>コース名（例: 「スペシャルディナーコース」）</li><li>価格（例: ¥8,800）</li><li>所要時間（例: 120 分）</li><li>人数範囲（例: 2〜8 名）</li><li>含まれる品目（カテゴリ別に設定）</li></ul></li><li><strong>【保存】</strong></li></ol><h3 id="_5-9-2-お客様視点" tabindex="-1">5-9-2. お客様視点 <a class="header-anchor" href="#_5-9-2-お客様視点" aria-label="Permalink to &quot;5-9-2. お客様視点&quot;">​</a></h3><p>予約 LP でコース選択肢として表示される → お客様が予約時に選択 → 来店時はコースの順番通りに料理が流れる（KDS でコース自動発火）</p><hr><h2 id="_5-10-顧客台帳-リピーター管理" tabindex="-1">5-10. 顧客台帳（リピーター管理） <a class="header-anchor" href="#_5-10-顧客台帳-リピーター管理" aria-label="Permalink to &quot;5-10. 顧客台帳（リピーター管理）&quot;">​</a></h2><p>過去に来店したお客様の情報を記録する機能。</p><h3 id="手順-1" tabindex="-1">手順 <a class="header-anchor" href="#手順-1" aria-label="Permalink to &quot;手順&quot;">​</a></h3><ol><li>【予約管理】 → 【顧客台帳】サブタブ</li><li>検索フィルタ（名前・電話・タグ）</li><li>顧客カードをタップ → 詳細画面</li><li>表示される情報: <ul><li>来店履歴（直近 50 件）</li><li>好み / アレルギー</li><li>タグ（VIP / リピーター / ブラックリスト）</li><li>内部メモ（スタッフ間の申し送り）</li><li>累計来店回数・累計金額</li></ul></li></ol><hr><h2 id="_5-11-vip-ブラックリストの設定" tabindex="-1">5-11. VIP / ブラックリストの設定 <a class="header-anchor" href="#_5-11-vip-ブラックリストの設定" aria-label="Permalink to &quot;5-11. VIP / ブラックリストの設定&quot;">​</a></h2><h3 id="_5-11-1-vip-設定" tabindex="-1">5-11-1. VIP 設定 <a class="header-anchor" href="#_5-11-1-vip-設定" aria-label="Permalink to &quot;5-11-1. VIP 設定&quot;">​</a></h3><ol><li>顧客詳細画面 → <strong>VIP</strong> チェックボックス ON</li><li>保存</li><li>予約時にガントで <strong>★VIP</strong> バッジ表示</li><li>スタッフが特別対応しやすくなる</li></ol><h3 id="_5-11-2-ブラックリスト-manager-以上のみ" tabindex="-1">5-11-2. ブラックリスト（manager 以上のみ） <a class="header-anchor" href="#_5-11-2-ブラックリスト-manager-以上のみ" aria-label="Permalink to &quot;5-11-2. ブラックリスト（manager 以上のみ）&quot;">​</a></h3><p>2 回以上無断キャンセルをしたお客様や、店舗運営に支障があるお客様をブロックできます。</p><ol><li>顧客詳細画面 → <strong>ブラックリスト</strong> チェックボックス ON</li><li><strong>理由</strong>を入力（例: 「過去 3 回無断キャンセル」）</li><li>保存</li><li>以降、この電話番号からの予約 LP からの申込は自動拒否</li></ol><hr><h2 id="_5-12-予約金-デポジット-の設定" tabindex="-1">5-12. 予約金（デポジット）の設定 <a class="header-anchor" href="#_5-12-予約金-デポジット-の設定" aria-label="Permalink to &quot;5-12. 予約金（デポジット）の設定&quot;">​</a></h2><p>大人数予約や、無断キャンセルが多い店舗向けの設定です。</p><h3 id="_5-12-1-有効化" tabindex="-1">5-12-1. 有効化 <a class="header-anchor" href="#_5-12-1-有効化" aria-label="Permalink to &quot;5-12-1. 有効化&quot;">​</a></h3><ol><li>【予約管理】 → 【予約設定】サブタブ</li><li><strong>「予約金を徴収する」</strong> チェックボックス ON</li><li>1 人あたりの金額を入力（例: ¥2,000 / 人）</li><li>徴収開始人数を入力（例: 6 名以上）</li><li><strong>【保存】</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">Stripe 設定済みであることが前提</p><p>予約金徴収は Stripe 経由で処理するため、<strong>先に Stripe 設定（21 章）を完了</strong>してください。Stripe 未設定だと予約金 ON にできません。</p></div><h3 id="_5-12-2-予約金の動き" tabindex="-1">5-12-2. 予約金の動き <a class="header-anchor" href="#_5-12-2-予約金の動き" aria-label="Permalink to &quot;5-12-2. 予約金の動き&quot;">​</a></h3><table tabindex="0"><thead><tr><th>イベント</th><th>POSLA の動作</th></tr></thead><tbody><tr><td>予約完了時</td><td>カードの有効性を確認し、予約金枠を確保</td></tr><tr><td>来店・着席時</td><td>予約金枠を解除し、課金なし</td></tr><tr><td>無断キャンセル時</td><td>予約金を請求</td></tr><tr><td>期限内キャンセル</td><td>予約金枠を解除し、課金なし</td></tr><tr><td>期限外キャンセル</td><td>予約金を請求</td></tr></tbody></table><hr><h2 id="_5-13-ai-予約-お客様の自由文入力" tabindex="-1">5-13. AI 予約（お客様の自由文入力） <a class="header-anchor" href="#_5-13-ai-予約-お客様の自由文入力" aria-label="Permalink to &quot;5-13. AI 予約（お客様の自由文入力）&quot;">​</a></h2><p>お客様が「明日 19 時 2 名田中」のように自由文で予約できる機能。</p><h3 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h3><ol><li>お客様が予約 LP を開く</li><li>画面右下の <strong>【💬 AI で予約】</strong> ボタン</li><li>自由文で希望を入力</li><li>Gemini AI が解析 → 日時・人数・名前を抽出</li><li>確認画面で間違いがないかチェック</li><li>【予約する】</li></ol><h3 id="店舗側設定" tabindex="-1">店舗側設定 <a class="header-anchor" href="#店舗側設定" aria-label="Permalink to &quot;店舗側設定&quot;">​</a></h3><ul><li>【予約管理】 → 【予約設定】 → <strong>「AI チャット予約」</strong> トグル ON/OFF で有効化</li></ul><h2 id="_5-14-予約リマインダーメール" tabindex="-1">5-14. 予約リマインダーメール <a class="header-anchor" href="#_5-14-予約リマインダーメール" aria-label="Permalink to &quot;5-14. 予約リマインダーメール&quot;">​</a></h2><p>予約日時の前にお客様にメール通知。</p><h3 id="設定" tabindex="-1">設定 <a class="header-anchor" href="#設定" aria-label="Permalink to &quot;設定&quot;">​</a></h3><ol><li>【予約管理】 → 【予約設定】</li><li><strong>24 時間前リマインダー</strong> トグル ON</li><li><strong>2 時間前リマインダー</strong> トグル ON</li><li>【保存】</li></ol><h3 id="動作" tabindex="-1">動作 <a class="header-anchor" href="#動作" aria-label="Permalink to &quot;動作&quot;">​</a></h3><p>設定を有効にすると、指定したタイミングで自動送信されます。初回設定に不安がある場合は POSLA 運営にご相談ください。</p><hr><h2 id="_5-15-よくある質問" tabindex="-1">5-15. よくある質問 <a class="header-anchor" href="#_5-15-よくある質問" aria-label="Permalink to &quot;5-15. よくある質問&quot;">​</a></h2><p><strong>Q1. お客様が予約後に来ないとき、どう対応する？</strong></p><p>A1. 予約時刻から 30 分経ったらガントで予約ブロックをタップ → <strong>【無断キャンセル】</strong>。予約金設定があれば、設定に従って請求されます。</p><p><strong>Q2. 大人数予約（10 名以上）はどうする？</strong></p><p>A2. 複数テーブル連結予約が可能（最大 3 テーブル）。予約登録時にテーブル複数チェックで割り当てます。無断キャンセルリスクが高いため、予約金を設定する運用がおすすめです。</p><p><strong>Q3. AI 予約で誤解析されたら？</strong></p><p>A3. お客様が確認画面で修正できます。送信後は店舗側で修正も可。</p><p><strong>Q4. 電話予約でテーブルを決めずに予約受けた。後からどう割当てる？</strong></p><p>A4. ガント画面で予約ブロック →【✏️ 変更】でテーブル追加。または、お客様が来店時に手動着席でテーブル指定。</p><p><strong>Q5. 予約金を取りたくないが、無断キャンセルが多くて困る</strong></p><p>A5. ブラックリスト機能で問題のあるお客様をブロックできます。2 回以上無断キャンセルしたお客様は、電話番号をもとにブラックリスト登録を検討してください。</p><hr><h2 id="_5-16-次のページへ" tabindex="-1">5-16. 次のページへ <a class="header-anchor" href="#_5-16-次のページへ" aria-label="Permalink to &quot;5-16. 次のページへ&quot;">​</a></h2><p>→ <a href="./part6-settings.html">Part 6: 店舗の設定</a></p>`,129)])])}const u=a(o,[["render",n]]);export{c as __pageData,u as default};
